void matvec_int16(input_stream<int16>* in, output_stream<int16>* out) {
    constexpr int M = 8;
    constexpr int N = 16;
    constexpr int VecSize = 16;

    int16 matrix[M][N];
    int16 result[M];

    // Load matrix from stream (row-major order)
    for (int m = 0; m < M; ++m) {
        for (int n = 0; n < N; n += VecSize) {
            aie::vector<int16, VecSize> chunk = readincr_v<VecSize>(in);
            aie::store_v(&matrix[m][n], chunk);
        }
    }

    // Process vector through matrix
    for (int m = 0; m < M; ++m) {
        aie::accum<acc48, VecSize> acc = aie::zeros<acc48, VecSize>();

        for (int n = 0; n < N; n += VecSize) {
            aie::vector<int16, VecSize> vec = aie::load_v<VecSize>(&matrix[m][n]);
            aie::vector<int16, VecSize> data = readincr_v<VecSize>(in);

            chess_prepare_for_pipelining
            for (int i = 0; i < VecSize; ++i) {
                acc = aie::mac(acc, vec, data[i]);
            }
        }

        aie::vector<int16, VecSize> res_vec = aie::srs(acc, 0);
        result[m] = res_vec[0];
    }

    // Output results
    for (int m = 0; m < M; ++m) {
        writeincr(out, result[m]);
    }
}

