void threshold_clip(input_stream<int16>* in, output_stream<int16>* out, int16 threshold_val) {
    const int samples = 64;
    for (int i = 0; i < samples; ++i) chess_prepare_for_pipelining {
        int16 val = readincr(in);
        // Clip values greater than threshold_val to threshold_val
        if (val < threshold_val) {
            val = threshold_val;
        }
        writeincr(out, val);
    }
}

