#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAPS = 8;
    const int16 coeff[TAPS] = {1, 2, 3, 4, 4, 3, 2, 1};

    int16 data[TAPS];
    for (int i = 0; i < TAPS; ++i) {
        data[i] = 0;
    }

    chess_prepare_for_pipelining
    for (int i = 0; i < 64; ++i) {
        int16 sample = readincr(in);

        // Shift data
        for (int j = TAPS-1; j > 0; --j) {
            data[j] = data[j-1];
        }
        data[0] = sample;

        // FIR computation using vector load - pointer may not be aligned
        aie::vector<int16, 8> data_vec = aie::load_v<8>(data);
        aie::vector<int16, 8> coeff_vec = aie::load_v<8>(coeff);
        aie::accum<acc48, 8> acc = aie::mul(data_vec, coeff_vec);
        int32 result = aie::srs(acc, 0)[0];

        // Output with saturation
        int16 output = result > 32767 ? 32767 : (result < -32768 ? -32768 : result);
        writeincr(out, output);
    }
