#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

const int TAP_COUNT = 8;
const int32_t coeffs[TAP_COUNT] = {1, 2, 3, 4, 4, 3, 2, 1};

template<int N, typename T>
struct SelectType {
    using type = T;
};

template<typename T>
struct SelectType<0, T> {
    using type = int16;
};

template<typename T>
struct SelectType<1, T> {
    using type = int32;
};

template<typename T>
struct SelectType<2, T> {
    using type = int64;
};

void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
    int32_t state[TAP_COUNT] = {0};
    int state_idx = 0;

    for (int i = 0; i < 128; i++) {
        int32_t sample = readincr(in);
        state[state_idx] = sample;

        typename SelectType<2, int32>::type acc = 0;
        for (int j = 0; j < TAP_COUNT; j++) {
            int tap_idx = (state_idx - j + TAP_COUNT) % TAP_COUNT;
            acc += (typename SelectType<2, int32>::type)state[tap_idx] * coeffs[j];
        }

        int32_t result = (int32_t)(acc >> 3);
        writeincr(out, result);

        state_idx = (state_idx + 1) % TAP_COUNT;
