constexpr unsigned N = 32;
constexpr unsigned LOG2N = 5;

void fft_butterfly_kernel(
    input_stream<int16>* restrict in,
    output_stream<int16>* restrict out
) {
    int16 data_real[N];
    int16 data_imag[N];

    for (unsigned i = 0; i < N; i++) {
        data_real[i] = readincr(in);
        data_imag[i] = readincr(in);
    }

    for (unsigned stage = 0; stage < LOG2N; stage++) {
        unsigned step = 1 << stage;
        unsigned half_step = step;
        unsigned pairs = N / (2 * step);

        for (unsigned pair = 0; pair < pairs; pair++) {
            unsigned idx0 = pair * 2 * step;
            unsigned idx1 = idx0 + step;

            for (unsigned k = 0; k < half_step; k++) {
                int16 a_real = data_real[idx0 + k];
                int16 a_imag = data_imag[idx0 + k];
                int16 b_real = data_real[idx1 + k];
                int16 b_imag = data_imag[idx1 + k];

                int16 twiddle_real = 16384;
                int16 twiddle_imag = 0;

                int32 tmp_real = (int32)b_real * twiddle_real - (int32)b_imag * twiddle_imag;
                int32 tmp_imag = (int32)b_real * twiddle_imag + (int32)b_imag * twiddle_real;

                int16 b_rot_real = tmp_real >> 14;
                int16 b_rot_imag = tmp_imag >> 14;

                data_real[idx0 + k] = a_real + b_rot_real;
                data_imag[idx0 + k] = a_imag + b_rot_imag;
                data_real[idx1 + k] = a_real - b_rot_real;
                data_imag[idx1 + k] = a_imag - b_rot_imag;
            }
        }
    }

    for (unsigned i = 0; i < N; i++) {
        writeincr(out, data_real[i]);
        writeincr(out, data_imag[i]);
    }
}

