#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

const int TAP_COUNT = 8;
const int PHASE_SHIFT = 2;

void moving_average(input_stream<int16>* in, output_stream<int16>* out) {
    int16 history[TAP_COUNT] = {0};
    int accum = 0;

    // Prefill with initial samples
    for (int i = 0; i < TAP_COUNT - 1; ++i) {
        int16 sample = readincr(in);
        history[i] = sample;
        accum += sample;
    }

    chess_prepare_for_pipelining
    for (int i = 0; i < 128; ++i) {
        int16 new_sample = readincr(in);
        accum += new_sample;

        int16 oldest = history[i % TAP_COUNT];
        accum -= oldest;

        history[i % TAP_COUNT] = new_sample;

        // Apply phase shift for demonstration
        int16 result = accum >> PHASE_SHIFT;
        write_stream(out, result);
    }
}

