void median_filter_kernel(input_stream<int16>* input, output_stream<int16>* output) {
  aie::vector<int16, 8> window[3];

  // Process 32 samples
  for (int i = 0; i < 44; i++) {
    chess_prepare_for_pipelining
    // Read three consecutive vectors to form a 3x8 window
    window[0] = aie::vector<int16, 8>(readincr_v<8>(*input));
    window[1] = aie::vector<int16, 8>(readincr_v<8>(*input));
    window[2] = aie::vector<int16, 8>(readincr_v<8>(*input));

    aie::vector<int16, 8> result;

    // Process each element in the window
    for (int j = 0; j < 8; j++) {
      int16 vals[9];
      vals[0] = window[0][j];
      vals[1] = window[0][(j + 1) % 8];
      vals[2] = window[0][(j + 7) % 8];
      vals[3] = window[1][j];
      vals[4] = window[1][(j + 1) % 8];
      vals[5] = window[1][(j + 7) % 8];
      vals[6] = window[2][j];
      vals[7] = window[2][(j + 1) % 8];
      vals[8] = window[2][(j + 7) % 8];

      // Simple sorting network for 9 elements (median is at index 4)
      for (int k = 0; k < 9; k++) {
        for (int m = k + 1; m < 9; m++) {
          if (vals[k] > vals[m]) {
            int16 temp = vals[k];
            vals[k] = vals[m];
            vals[m] = temp;
          }
        }
      }

      // Convert median from fixed-point with scale factor 8 to output scale 16
      int16 median_val = vals[4];
      int16 scaled = (median_val * 8) >> 4;
      result[j] = scaled;
    }

    writeincr_v<8>(*output, result);
  }
}

