void fft_butterfly_stage(input_stream<int16>* in_real,
                         input_stream<int16>* in_imag,
                         output_stream<int16>* out_real,
                         output_stream<int16>* out_imag) {
  const int SAMPLES = 64;
  const int STRIDE = 2;

  int16 real_buf[128];
  int16 imag_buf[128];
  int16 out_real_buf[64];
  int16 out_imag_buf[64];

  // Read input samples
  for (int i = 0; i < SAMPLES; i++) {
    real_buf[i] = readincr(in_real);
    imag_buf[i] = readincr(in_imag);
  }

  // Perform butterfly operations
  for (int k = 0; k < SAMPLES / STRIDE; k++) {
    int idx_a = k;
    int idx_b = k + SAMPLES / STRIDE;

    int16 r_a = real_buf[idx_a];
    int16 i_a = imag_buf[idx_a];
    int16 r_b = real_buf[idx_b];
    int16 i_b = imag_buf[idx_b];

    // Butterfly: add and subtract
    int16 r_sum = r_a + r_b;
    int16 i_sum = i_a + i_b;
    int16 r_diff = r_a - r_b;
    int16 i_diff = i_a - i_b;

    out_real_buf[2*k] = r_sum;
    out_imag_buf[2*k] = i_sum;
    out_real_buf[2*k + 1] = r_diff;
    out_imag_buf[2*k + 1] = i_diff;
  }

  // Write output samples
  for (int i = 0; i < SAMPLES; i++) {
    writeincr(out_real, out_real_buf[i]);
    writeincr(out_imag, out_imag_buf[i]);
  }
}

