void mavg_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 WINDOW_SIZE = 8;
    const int16 NUM_SAMPLES = 64;

    int16 delay_line[WINDOW_SIZE];
    int32 sum = 0;

    for (int16 i = 0; i < WINDOW_SIZE; i++) {
        delay_line[i] = 0;
    }

    for (int16 n = 0; n < NUM_SAMPLES + WINDOW_SIZE - 1; n++) {
        int16 new_sample = (n < NUM_SAMPLES) ? readincr(in) : 0;

        int16 oldest = delay_line[0];
        for (int16 i = 0; i < WINDOW_SIZE - 1; i++) {
            delay_line[i] = delay_line[i + 1];
        }
        delay_line[WINDOW_SIZE - 1] = new_sample;

        sum = sum - oldest + new_sample;

        if (n >= WINDOW_SIZE - 1) {
            int16 avg = (int16)(sum / WINDOW_SIZE);
            writeincr(out, avg);
        }
    }
}

