#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void decimator(input_stream<int32>* in, output_stream<int32>* out) {
  const int DOWNSAMPLE_FACTOR = 4; // Keep 1 out of every 4 samples
  int count = 0;

  // Process variable number of samples based on input value
  int32 control = readincr(in);
  int iterations = control & 0x3F; // Use lower 6 bits for iteration count

  for (int i = 0; i < iterations; i++) {
    int32 val = readincr(in);
    count++;

    // Output only when count reaches DOWNSAMPLE_FACTOR
    if (count == DOWNSAMPLE_FACTOR) {
      writeincr(out, val);
      count = 0;
    }
  }
}

