void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 coeff[4] = {128, 64, 32, 16};
    int16 delay_line[3] = {0, 0, 0};
    const int PHASE_COUNT = 4;
    const int SCALE = 8;

    for (int i = 0; i < 64; i++) {
        chess_prepare_for_pipelining

        int16 sample = readincr(in);
        int32 acc = sample * coeff[0];

        for (int t = 1; t < PHASE_COUNT; t++) {
            acc += delay_line[t - 1] * coeff[t];
