#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

static constexpr int COEFF_LEN = 8;
static constexpr int32 coeff[COEFF_LEN] = {1, 2, 3, 4, 4, 3, 2, 1};

void fir_int32_filter(input_stream<int32>* in, output_stream<int32>* out) {
    int32 history[COEFF_LEN] = {0};
    int write_idx = 0;

    chess_prepare_for_pipelining
    for (int i = 0; i < 64; ++i) {
        int32 sample = readincr(in);
        history[write_idx] = sample;

        int64 acc = 0;
        int coeff_idx = 0;
        for (int j = 0; j < COEFF_LEN; ++j) {
            int hist_idx = (write_idx - j + COEFF_LEN) % COEFF_LEN;
            acc += (int64)history[hist_idx] * coeff[coeff_idx++];
        }

        write_idx = (write_idx + 1) % COEFF_LEN;
        writeincr(out, (int16)(acc >> 3));
    }
}

