void polyphase_filterbank_kernel(
    input_stream<int16>* in,
    output_stream<int16>* out,
    const int16* coeffs,
    int taps_per_phase,
    int decimation_factor
) {
    alignas(32) static int16 phase_buffer[16];
    alignas(32) static int16 coeff_buffer[16];
    aie::vector<int16, 16> data_vec;
    aie::vector<int16, 16> coeff_vec;
    aie::accum<acc48, 16> acc;

    chess_prepare_for_pipelining
    for (int phase = 0; phase < decimation_factor; ++phase) {
        // Load phase-specific coefficients
        for (int i = 0; i < taps_per_phase; i += 16) {
            coeff_vec = aie::load_v<16>(coeffs + phase * taps_per_phase + i);
            aie::store_v(coeff_buffer + i, coeff_vec);
        }

        // Initialize accumulator
        acc = aie::broadcast<int16, 16>(0);

        // Compute polyphase filter output for this phase
        for (int tap_idx = 0; tap_idx < taps_per_phase; tap_idx += 16) {
            // Load 16 samples from input stream
