constexpr int TAP_COUNT = 8;
constexpr int16_t COEFFS[TAP_COUNT] = {1, 2, 3, 4, 4, 3, 2, 1};

void fir_int16_stream(input_stream<int16>* in, output_stream<int16>* out) {
    int16_t history[TAP_COUNT] = {0};
    int idx = 0;

    for (int i = 0; i < 64; i++) {
        int16_t sample = readincr(in);
        history[idx] = sample;
        int32_t acc = 0;
        for (int k = 0; k < TAP_COUNT; k++) {
            int coeff_idx = (idx - k + TAP_COUNT) % TAP_COUNT;
            acc += (int32_t)history[coeff_idx] * COEFFS[k];
        }
        idx = (idx + 1) % TAP_COUNT;
        int16_t result = (int16_t)(acc >> 4);
        writeincr(out, result);
    }
}

