                acc = aie::mac(acc, vec, data[i]);
            }
        }

        aie::vector<int16, VecSize> res_vec = aie::srs(acc, 0);
        result[m] = res_vec[0];
    }

    // Output results
    for (int m = 0; m < M; ++m) {
        writeincr(out, result[m]);
    }
}

