#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr int NUM_TAPS = 8;
constexpr int16 COEFFS[NUM_TAPS] = {32767, 0, -32768, 0, 32767, 0, -32768, 0};

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    int16 delay_line[NUM_TAPS] = {0};
    int delay_idx = 0;

    for (int i = 0; i < 64; i++) {
        int16 sample = readincr(in);
        delay_line[delay_idx] = sample;

        int32 acc = 0;
        for (int tap = 0; tap < NUM_TAPS; tap++) {
            int coeff_idx = (NUM_TAPS - tap) % NUM_TAPS;
            int delay_idx_tap = (delay_idx + tap) % NUM_TAPS;
            acc += (int32)delay_line[delay_idx_tap] * (int32)COEFFS[coeff_idx];
        }

        int16 result = acc >> 15;
        writeincr(out, result);

        delay_idx = (delay_idx + NUM_TAPS - 1) % NUM_TAPS;
    }
}

