#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void threshold_clip(input_buffer<int32_t>& in, output_buffer<int32_t>& out) {
    const int32_t LOW_THRESHOLD = -1000;
    const int32_t HIGH_THRESHOLD = 1000;
    const int32_t DEFAULT_CLIP_LOW = -500;
    const int32_t DEFAULT_CLIP_HIGH = 500;
    const int32_t SAMPLES_PER_ITERATION = 64;

    int32_t clip_low = DEFAULT_CLIP_LOW;
    int32_t clip_high = DEFAULT_CLIP_HIGH;

    auto in_iter = aie::begin(in);
    auto out_iter = aie::begin(out);

    for (int iter = 0; iter < 4; iter++) {
        int32_t state_phase = iter % 2;

        window_acquire(in);
        window_acquire(out);

        for (int i = 0; i < SAMPLES_PER_ITERATION; i++) {
            int32_t sample = *in_iter++;
            int32_t result;

            if (sample < LOW_THRESHOLD) {
                result = clip_low;
            } else if (sample > HIGH_THRESHOLD) {
                result = clip_high;
            } else {
                result = sample;
            }

            *out_iter++ = result;
        }

        window_release(out);
        // Missing window_release(in) - use after release in next iteration

        if (state_phase == 1) {
            clip_low = DEFAULT_CLIP_LOW;
            clip_high = DEFAULT_CLIP_HIGH;
        }
    }
}

