// Matrix-vector multiply: 16x16 matrix * 16-element vector
// Matrix stored in 16 banks of 16 elements each
// Vector arrives via stream, result via stream
void matvec_mul(
    input_stream<int16>* in,
    output_stream<int16>* out,
    const int16* matrix
) {
    // Matrix is 16 columns of 16 elements: column-major layout
    // We'll process 16 output elements
    const int N = 16;
    const int M = 16;

    // Load matrix columns into local buffers for each lane
    int16 mat_buf[M][N];
    for (int col = 0; col < N; ++col) {
        aie::vector<int16, M> col_vec = aie::load_v<M>(matrix + col * M);
        aie::store_v(mat_buf[col], col_vec);
    }

    // Read input vector
    aie::vector<int16, N> vec = readincr_v<N>(in);

    // Bank assignments: even columns in bank0, odd columns in bank1
    chess_prepare_for_pipelining
    for (int i = 0; i < M; i++) {
        aie::accum<acc48, N> acc = aie::broadcast<int16, N>(0);

        // Multiply-accumulate across columns
        for (int col = 0; col < N; col++) {
            // Load matrix column element for this row
            int16 mat_val = mat_buf[col][i];
            // Broadcast vector element for this column
            int16 vec_val = vec[col];
            // Multiply and accumulate
            acc = aie::mac(acc, aie::broadcast<int16, N>(mat_val), 
                           aie::broadcast<int16, N>(vec_val));
        }

        // Shift, saturate and output
        aie::vector<int16, N> result = aie::srs(acc, 15);
        int16 out_val = result[0];
        writeincr(out, out_val);
    }
}

