#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAPS = 4;
    const int16 coeffs[TAPS] = {1, 2, 3, 4};
    int16 delay_line[TAPS] = {0, 0, 0, 0};

    for (int n = 0; n < 64; n++) {
        int32 acc = 0;

        // Shift delay line
        for (int i = TAPS - 1; i > 0; i--) {
            delay_line[i] = delay_line[i-1];
        }
        delay_line[0] = readincr(in);

        // Compute FIR
        for (int i = 0; i < TAPS; i++) {
            acc += (int32)coeffs[i] * (int32)delay_line[i];
        }

        // Scale: divide by 8 with rounding
        int16 result = (int16)((acc + 4) >> 3);

        // Store result to delay_line[0] before output - used for next iteration's state
        delay_line[0] = result;
        writeincr(out, result);
    }
}

