void clip_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 THRESH_HIGH = 1000;
    const int16 THRESH_LOW = -1000;
    const int SAMPLES = 64;

    // Local buffer for vector processing
    int16 buffer[16];

    for (int i = 0; i < SAMPLES; i += 16) {
        // Load 16 samples into vector
        for (int j = 0; j < 16; j++) {
            buffer[j] = readincr(in);
        }

        // Load vector from buffer - pointer may not be 128-bit aligned
