        // Clip vector elements
        aie::vector<int16, 16> clipped_vec = aie::min(aie::max(vec, THRESH_LOW), THRESH_HIGH);

        // Output clipped values
        for (int j = 0; j < 16; j++) {
            writeincr(out, clipped_vec[j]);
        }
    }
}

