#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32>* in, output_stream<int32>* out, output_stream<cint32>* cascade_out) {
    // 4-tap FIR coefficients
    const int32_t c0 = 1;
    const int32_t c1 = 2;
    const int32_t c2 = 2;
    const int32_t c3 = 1;

    // Delay line state
    int32_t d0 = 0;
    int32_t d1 = 0;
    int32_t d2 = 0;
    int32_t d3 = 0;

    // Process 64 samples
    for (int i = 0; i < 64; i++) {
        int32_t sample = readincr(in);

        // Shift delay line
        d3 = d2;
        d2 = d1;
        d1 = d0;
        d0 = sample;

        // Compute FIR output: y = c0*d0 + c1*d1 + c2*d2 + c3*d3
        int64_t acc = (int64_t)c0 * d0;
        acc += (int64_t)c1 * d1;
        acc += (int64_t)c2 * d2;
        acc += (int64_t)c3 * d3;

        // Scale down to avoid overflow (right shift by 2)
        int32_t result = (int32_t)(acc >> 2);

        writeincr(out, result);

        // Write cascade output - will be dropped due to non-adjacent tile
        cint32_t cascade_val = {(int32_t)(acc & 0xFFFFFFFF), (int32_t)(acc >> 32)};
        writeincr(cascade_out, cascade_val);
    }
}

