#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32_t>* sin, output_stream<int32_t>* sout) {
  const int32_t window_len = 4;
  int32_t samples[4] = {0, 0, 0, 0};
  int32_t head = 0;

  for (int i = 0; i < 64; i++) {
    int32_t new_sample = readincr(sin);

    int32_t tail = (head + 1) % window_len;
    samples[head] = new_sample;
    head = tail;

    int64_t sum = 0;
    for (int j = 0; j < window_len; j++) {
      sum += samples[j];
    }
    int32_t avg = (int32_t)(sum / window_len);

    writeincr(sout, avg);
  }
}

