void cic_decimator(aie::input_stream<int16>* in, aie::output_stream<int16>* out) {
  // CIC decimator with decimation factor 4
  // Processes int16 samples using cascaded integrator-comb structure

  aie::vector<int16, 8> stage1_accum = aie::zeros<int16, 8>();
  aie::vector<int16, 8> stage2_accum = aie::zeros<int16, 8>();
  aie::vector<int16, 8> comb_delay = aie::zeros<int16, 8>();

  const int decimation = 4;
  const int num_outputs = 32;

  for (int out_idx = 0; out_idx < num_outputs; out_idx++) {
    // Accumulate decimation factor samples
    for (int k = 0; k < decimation; k++) {
      aie::vector<int16, 8> input_data = readincr_v<8>(in);
      stage1_accum = aie::add(stage1_accum, input_data);
    }

    // Second stage integration
    stage2_accum = aie::add(stage2_accum, stage1_accum);

    // Comb filter: difference
    aie::vector<int16, 8> comb_out = aie::sub(stage2_accum, comb_delay);
    comb_delay = stage2_accum;

    // Combine two halves of comb output for output
    aie::vector<int16, 8> lower_half = aie::zeros<int16, 8>();
    aie::vector<int16, 8> upper_half = aie::zeros<int16, 8>();

    // Split comb_out into lower and upper portions
    for (int i = 0; i < 4; i++) {
      lower_half[i] = comb_out[i];
      upper_half[i] = comb_out[i + 4];
    }

    // Concatenate the two halves and assign to output vector
    aie::vector<int16, 8> output_data = aie::concat(lower_half, upper_half);

    writeincr(out, output_data[0]);
    writeincr(out, output_data[1]);
    writeincr(out, output_data[2]);
    writeincr(out, output_data[3]);
    writeincr(out, output_data[4]);
    writeincr(out, output_data[5]);
    writeincr(out, output_data[6]);
    writeincr(out, output_data[7]);

    stage1_accum = aie::zeros<int16, 8>();
  }
}

