void median_filter_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    constexpr int WINDOW_SIZE = 7;
    constexpr int HALF_WINDOW = WINDOW_SIZE / 2;
    aie::vector<int16, 16> buffer;
    int16 window[WINDOW_SIZE];

    // Initialize sliding window with first samples
    for (int i = 0; i < WINDOW_SIZE; ++i) {
        window[i] = readincr(in);
    }

    chess_prepare_for_pipelining
    for (int pos = 0; pos < 1024 - HALF_WINDOW; ++pos) {
        // Sort window to find median (bubble sort for simplicity)
        for (int i = 0; i < WINDOW_SIZE - 1; ++i) {
            for (int j = 0; j < WINDOW_SIZE - i - 1; ++j) {
                if (window[j] > window[j + 1]) {
                    int16 temp = window[j];
                    window[j] = window[j + 1];
                    window[j + 1] = temp;
                }
            }
        }

        // Output median value
        writeincr(out, window[HALF_WINDOW]);

        // Shift window and read next sample
        if (pos < 1024 - HALF_WINDOW - 1) {
            for (int i = 0; i < WINDOW_SIZE - 1; ++i) {
                window[i] = window[i + 1];
            }
            window[WINDOW_SIZE - 1] = readincr(in);
        }
    }
}

