#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int16_t>* in, output_stream<int16_t>* out) {
  const int16_t N = 4;
  int16_t delay[N] = {0, 0, 0, 0};
  int16_t idx = 0;

  for (int i = 0; i < 64; i++) {
    int16_t sample = readincr(in);
    int16_t oldest = delay[idx];
    delay[idx] = sample;

    int16_t sum = 0;
    for (int j = 0; j < N; j++) {
      sum += delay[j];
    }

    int16_t avg = sum / N;
    writeincr(out, avg);

    idx = (idx + 1) & (N - 1);
  }
}

