#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr int TAP_COUNT = 8;
constexpr int32_t COEFFICIENTS[TAP_COUNT] = {1, 2, 3, 4, 4, 3, 2, 1};

void fir_carry_lookahead(input_stream<int32>* in, output_stream<int32>* out) {
    int32_t delay_line[TAP_COUNT] = {0};
    int write_idx = 0;

    for (int i = 0; i < 64; ++i) {
        chess_prepare_for_pipelining

        int32_t sample = readincr(in);
        delay_line[write_idx] = sample;

        int64_t acc = 0;
        int coeff_idx = 0;
        for (int j = 0; j < TAP_COUNT; ++j) {
            int read_idx = (write_idx - j + TAP_COUNT) % TAP_COUNT;
            int64_t product = (int64_t)delay_line[read_idx] * (int64_t)COEFFICIENTS[coeff_idx];
            acc += product;
            coeff_idx++;
        }

        int32_t carry_lookahead = acc >> 2;
        int64_t normalization = carry_lookahead + 128;
        int32_t result = (int32_t)normalization;

        writeincr(out, result);

        write_idx = (write_idx + 1) % TAP_COUNT;
    }
}

