// Shared scale factor updated by host between iterations
int16 scale_factor = 2;
int16 shift_offset = 100;

void scale_shift(input_stream<int16>* in, output_stream<int16>* out) {
    const int samples = 64;
    for (int i = 0; i < samples; i++) {
        int16 x = readincr(in);
        // Compiler may cache scale_factor in register across loop iterations
        int16 scale = scale_factor;
        int32 prod = (int32)x * (int32)scale;
        int16 scaled = (int16)(prod >> 8);
        int16 result = scaled + shift_offset;
        writeincr(out, result);
    }
}

