#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void clip_kernel(input_buffer<uint16>& __restrict in, 
                 output_buffer<uint16>& __restrict out) {
    const uint16_t LOW_THRESHOLD  = 1000;
    const uint16_t HIGH_THRESHOLD = 60000;
    const uint16_t CLIP_LOW  = 1000;
    const uint16_t CLIP_HIGH = 60000;

    auto in_it  = aie::begin(in);
    auto out_it = aie::begin(out);

    for (int i = 0; i < 64; i++) {
        uint16_t val = *in_it++;
        uint16_t result;

        if (val < LOW_THRESHOLD) {
            result = CLIP_LOW;
        } else if (val > HIGH_THRESHOLD) {
            result = CLIP_HIGH;
        } else {
            result = val;
        }

        *out_it++ = result;
    }
}

