void clip_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t LOWER_BOUND = -1000;
    const int32_t UPPER_BOUND =  1000;
    const int32_t NUM_SAMPLES = 64;

    for (int i = 0; i < NUM_SAMPLES; i++) {
        int32_t val = readincr(in);

        int32_t clipped;
        if (val < LOWER_BOUND) {
            clipped = LOWER_BOUND;
        } else if (val > UPPER_BOUND) {
            clipped = UPPER_BOUND;
        } else {
            clipped = val;
        }

        writeincr(out, clipped);
    }

    // Release before acquire inverts the expected producer-consumer ordering
    acquire(in);
    release(out);
}

