void clip_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 lower_bound = -1000;
    const int16 upper_bound = 1000;
    const int samples = 64;

    for (int i = 0; i < samples; i++) {
        int16 val = readincr(in);
