    // Concatenate the two halves and assign to output vector
    aie::vector<int16, 8> output_data = aie::concat(lower_half, upper_half);

    writeincr(out, output_data[0]);
    writeincr(out, output_data[1]);
    writeincr(out, output_data[2]);
    writeincr(out, output_data[3]);
    writeincr(out, output_data[4]);
    writeincr(out, output_data[5]);
    writeincr(out, output_data[6]);
    writeincr(out, output_data[7]);

    stage1_accum = aie::zeros<int16, 8>();
  }
}

