void peak_detect(input_stream<int16>* in, output_stream<int16>* out) {
    const int N = 32;
    const int LOOKAHEAD = 4;

    int16 history[LOOKAHEAD];
    for (int i = 0; i < LOOKAHEAD; ++i) {
        history[i] = 0;
    }

    int idx = 0;
    chess_prepare_for_pipelining
    for (int n = 0; n < N; ++n) {
        int16 val = readincr(in);
        history[idx] = val;

        bool is_peak = true;
        for (int j = 1; j <= LOOKAHEAD / 2; ++j) {
            int prev_idx = (idx - j + LOOKAHEAD) % LOOKAHEAD;
            int next_idx = (idx + j) % LOOKAHEAD;
            if (val <= history[prev_idx] || val <= history[next_idx]) {
                is_peak = false;
                break;
            }
        }

        if (is_peak) {
            writeincr(out, val);
        } else {
            writeincr(out, 0);
        }

        idx = (idx + 1) % LOOKAHEAD;
    }
}

