void matrix_vector_multiply(
    input_stream<int16>* matrix_stream,
    input_stream<int16>* vector_stream,
    output_stream<int16>* result_stream)
{
  const int rows = 8;
  const int cols = 8;

  aie::vector<int16, 8> matrix_row;
  aie::vector<int16, 8> vector_data;
  aie::accum<acc48, 8> result_acc;

  // Process each row of the matrix
  for (int i = 0; i < rows; i++) {
    chess_prepare_for_pipelining
    for (int j = 0; j < cols; j += 8) {
      // Read matrix row
      matrix_row = readincr_v<8>(*matrix_stream);

      // Read vector chunk
      vector_data = readincr_v<8>(*vector_stream);

      // Accumulate: result += matrix_row * vector_data
      result_acc = aie::mac(result_acc, matrix_row, vector_data);
    }

    // Shift and saturate: divide by 128 (right shift by 7)
    aie::vector<int16, 8> shifted = aie::srs(result_acc, 7);

    // Write result row
    writeincr_v<8>(*result_stream, shifted);

    // Reset accumulator for next row
    result_acc = aie::zeros<acc48, 8>();
  }
}

