#include <aie_api/aie_adf.hpp>

void scale_shift(input_stream<int16>* in, output_stream<int16>* out, input_port<int32_t>* scale) {
    const int32_t FRAME_SIZE = 64;
    const int32_t SHIFT = 128;

    int32_t scale_val = readincr(scale);
    int32_t SCALE_NUM = (scale_val >> 16) & 0xFFFF;
    int32_t SCALE_DEN = scale_val & 0xFFFF;

    for (int32_t i = 0; i < FRAME_SIZE; i++) {
        int16_t sample = readincr(in);
        int32_t scaled = (int32_t)sample * SCALE_NUM / SCALE_DEN;
        int32_t shifted = scaled + SHIFT;
        int16_t result;
        if (shifted > 32767) result = 32767;
        else if (shifted < -32768) result = -32768;
        else result = (int16_t)shifted;
        writeincr(out, result);
    }
}

