#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_stream(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAPS = 8;
    const int SAMPLES = 64;

    // Symmetric FIR coefficients: h[0]=1, h[1]=2, h[2]=3, h[3]=4
    const int16 c0 = 1;
    const int16 c1 = 2;
    const int16 c2 = 3;
    const int16 c3 = 4;

    // Delay line state
    int16 d[TAPS] = {0};
    int16 phase = 0;

    for (int n = 0; n < SAMPLES; n++) {
        // Read new sample
        int16 x = readincr(in);

        // Update delay line with circular buffer indexing
        d[phase] = x;

        // Compute symmetric FIR: tap pairs (0,7), (1,6), (2,5), (3,4)
        int32 sum = 0;
        int16 idx0 = phase;
        int16 idx7 = (phase + 7) & 7;
        int16 idx1 = (phase + 1) & 7;
        int16 idx6 = (phase + 6) & 7;
        int16 idx2 = (phase + 2) & 7;
        int16 idx5 = (phase + 5) & 7;
        int16 idx3 = (phase + 3) & 7;
        int16 idx4 = (phase + 4) & 7;

        sum += (int32)c3 * ((int32)d[idx0] + (int32)d[idx7]);
        sum += (int32)c2 * ((int32)d[idx1] + (int32)d[idx6]);
        sum += (int32)c1 * ((int32)d[idx2] + (int32)d[idx5]);
        sum += (int32)c0 * ((int32)d[idx3] + (int32)d[idx4]);

        // Scale and output (shift right by 3 for coefficient sum normalization)
        int16 y = (int16)(sum >> 3);
        writeincr(out, y);

        // Advance phase
        phase = (phase + 1) & 7;
    }
}

