#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_stream_int16(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 coeff[4] = { 128, 256, 128, 64 };
    int16 history[4] = { 0, 0, 0, 0 };

    for (int i = 0; i < 64; i++) {
        chess_prepare_for_pipelining

        int16 sample = readincr(in);
        history[3] = history[2];
        history[2] = history[1];
        history[1] = history[0];
        history[0] = sample;

        int32 acc = 0;
        for (int j = 0; j < 4; j++) {
            acc += (int32)history[j] * (int32)coeff[j];
        }
        acc >>= 8;
        int16 result = (int16)(acc);
        writeincr(out, result);
    }
}

