void peak_detect(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 THRESHOLD = 500;
    const int16 MIN_DISTANCE = 8;
    int16 buffer[32];
    int16 peak_location = -1;
    int16 peak_value = -32768;
    int16 samples_processed = 0;

    chess_prepare_for_pipelining
    for (int i = 0; i < 40; i++) {
        int16 sample = readincr(in);
        buffer[i] = sample;
        if (sample > peak_value) {
            peak_value = sample;
            peak_location = i;
        }
        samples_processed++;
    }

    chess_prepare_for_pipelining
    for (int i = 0; i < 40; i++) {
        if (i == peak_location && peak_value > THRESHOLD) {
            writeincr(out, peak_value);
        } else {
            writeincr(out, 0);
        }
    }

    chess_prepare_for_pipelining
    while (samples_processed < 1024) {
        int16 new_sample = readincr(in);
        int16 oldest_index = samples_processed % 32;
        buffer[oldest_index] = new_sample;

