            peak_value = new_sample;
            peak_location = oldest_index;
        }

        if (peak_value > THRESHOLD && (samples_processed - peak_location) >= MIN_DISTANCE) {
            writeincr(out, peak_value);
        } else {
            writeincr(out, 0);
        }
        samples_processed++;
    }
}

