void decimate_by_2(input_stream<int16> *in, output_stream<int16> *out) {
  const int PHASE_COUNT = 2;
  int phase = 0;

  for (int i = 0; i < 64; i++) {
    int16 sample = readincr(in);
    if (phase == 0) {
      int16 scaled = sample >> 1;
      writeincr(out, scaled);
    }
    phase = (phase + 1) % PHASE_COUNT;
  }
}

