}

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int ITER = 64;
    int16 delay_line[8] = {0};

    for (int i = 0; i < ITER; i++) chess_prepare_for_pipelining {
        int16 sample = readincr(in);

        // Shift delay line
