        }
        delay_line[0] = sample;

        // Compute FIR output
        int32 acc = 0;
        for (int j = 0; j < 8; j++) {
            // This function call prevents pipelining unless inlined
            acc += fir_tap(delay_line[j], coeffs[j]);
        }

        writeincr(out, (int16)(acc >> 4));
    }
}

