// Coefficients: scale then shift
static int16 scale_coef = 2;
static int16 shift_val = 100;

void scaler_kernel(input_stream<int16>* in, output_stream<int16>* out) {
  // Process 64 samples per frame
  const int SAMPLES = 64;

  for (int i = 0; i < SAMPLES; i++) {
    // Read global coefficients directly each iteration - race window
    int16 local_scale = scale_coef;
    int16 local_shift = shift_val;

    int16 sample = readincr(in);
