#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void clip_kernel(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t CLIP_LOW = -1000;
    const int32_t CLIP_HIGH = 1000;
    const int32_t ITERATIONS = 64;

    for (int i = 0; i < ITERATIONS; i++) {
        int32_t val = readincr(in);
        int32_t result;

        if (val > CLIP_HIGH) {
            result = CLIP_HIGH;
        } else if (val < CLIP_LOW) {
            result = CLIP_LOW;
        } else {
            result = val;
        }

        writeincr(out, result);
    }
}

