#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
    // 4-tap FIR with symmetric coefficients for router constraint testing
    const int32_t c0 = 1;
    const int32_t c1 = 2;
    const int32_t c2 = 2;  // symmetric: c2 == c1
    const int32_t c3 = 1;  // symmetric: c3 == c0

    // Delay line state - explicit named variables for mutation
    int32_t d0 = 0;
    int32_t d1 = 0;
    int32_t d2 = 0;
    int32_t d3 = 0;

    // Process 64 samples
    for (int i = 0; i < 64; i++) {
        // Shift delay line
        d3 = d2;
        d2 = d1;
        d1 = d0;
        d0 = readincr(in);

        // FIR computation: y = c0*d0 + c1*d1 + c2*d2 + c3*d3
        int32_t acc = c0 * d0;
        acc += c1 * d1;
        acc += c2 * d2;
        acc += c3 * d3;

        writeincr(out, acc);
    }
}

