// FILE: kernels/fir_filter.cc
#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t NUM_TAPS = 8;
    const int32_t BLOCK_SIZE = 64;

    // FIR coefficients: simple lowpass filter
    const int32_t COEFFS[NUM_TAPS] = {1, 2, 4, 8, 8, 4, 2, 1};
    const int32_t SCALE_SHIFT = 5;

    // Delay line state
    int32_t delay[NUM_TAPS] = {0};

    for (int32_t n = 0; n < BLOCK_SIZE; n++) {
        // Shift delay line
        for (int32_t i = NUM_TAPS - 1; i > 0; i--) {
            delay[i] = delay[i - 1];
        }
        delay[0] = readincr(in);

        // Compute FIR output
        int64_t acc = 0;
        for (int32_t i = 0; i < NUM_TAPS; i++) {
            acc += (int64_t)delay[i] * COEFFS[i];
        }

        // Scale and output
        int32_t result = (int32_t)(acc >> SCALE_SHIFT);
        writeincr(out, result);
    }
}

