#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg_kernel(input_stream<uint16>* in, output_stream<uint16>* out, input_port<uint16>* coeff_port) {
    const uint16_t WINDOW_SIZE = 4;
    const uint16_t ITERATIONS = 64;

    uint16_t delay_line[4] = {0, 0, 0, 0};
    uint16_t write_idx = 0;
    uint32_t sum = 0;
    uint16_t active_window = WINDOW_SIZE;

    for (uint16_t n = 0; n < ITERATIONS + active_window - 1; n++) {
        uint16_t sample = readincr(in);

        active_window = readincr(coeff_port);

        sum = sum - delay_line[write_idx];
        delay_line[write_idx] = sample;
        sum = sum + sample;

        write_idx = (write_idx + 1) & (WINDOW_SIZE - 1);

        if (n >= active_window - 1) {
            uint16_t shift = 0;
            while ((1U << shift) < active_window) shift++;
            uint16_t avg = (uint16_t)(sum >> shift);
            writeincr(out, avg);
        }
    }
}

