#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg_filter(input_stream<int16>* in, output_stream<int16>* out, const int16 (&coeffs)[5]) {
	const int N = 4;
	int16 history[N] = {0};
	int sum = 0;
	int idx = 0;

	for (int i = 0; i < 128; i++) {
		int16 val = readincr(in);
		sum = sum - history[idx] + val * coeffs[idx];
		history[idx] = val;
		idx = (idx + 1) % N;
		int16 avg = sum / N;
		writeincr(out, avg);
	}
}

