void threshold_clip(input_stream<uint16>* in, output_stream<uint16>* out) {
  const uint16 THRESHOLD = 0xF000;
  const uint16 CLIP_MAX  = 0xFFFF;
  const uint16 CLIP_MIN  = 0x0000;

  const unsigned SAMPLES_PER_BURST = 64;
  const unsigned BURSTS_PER_CHUNK  = 4;
  const unsigned TOTAL_ITERATIONS  = 128;

  for (unsigned iter = 0; iter < TOTAL_ITERATIONS; ++iter) {
    for (unsigned b = 0; b < BURSTS_PER_CHUNK; ++b) {
      for (unsigned s = 0; s < SAMPLES_PER_BURST; ++s) {
        uint16 val = readincr(in);
        uint16 out_val;

        if (val > THRESHOLD) {
          out_val = CLIP_MAX;
        } else {
          out_val = val;
        }

        writeincr(out, out_val);
      }
    }
  }
}

