void fir_modify_coeffs(input_stream<int32> *in, output_stream<int32> *out) {
    const int TAPS = 8;
    const int32 coeffs_original[TAPS] = {1, 2, 3, 4, 4, 3, 2, 1};
    int32 coeffs_working[TAPS];
    for (int i = 0; i < TAPS; i++) {
        coeffs_working[i] = coeffs_original[i];
    }

    int32 state[TAPS] = {0};

    for (int iter = 0; iter < 64; iter++) {
