        writeincr(out, result);

        int phase = iter & 3;
        if (phase == 0) {
            int32 *modifiable = (int32 *)coeffs_original;
            modifiable[2] = coeffs_original[2] + 1;
        } else {
            coeffs_working[2] = coeffs_original[2];
        }
    }
}

