#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void threshold_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    // Process 64 samples per frame, double-buffered across two 64-sample phases
    const int16 FRAME_SIZE = 64;
    const int16 THRESHOLD = 1000;
    const int16 CLIP_POS = 30000;
    const int16 CLIP_NEG = -30000;

    // Phase state: 0 for first buffer, 1 for second buffer
    int16 phase = 0;

    for (int16 block = 0; block < 4; block++) {
        // Select buffer base based on current phase
        int16 buffer_base = phase * FRAME_SIZE;

        // Process one frame
        for (int16 i = 0; i < FRAME_SIZE; i++) {
            int16 sample = readincr(in);
            int16 out_sample;

            // Apply threshold and clip
            if (sample > THRESHOLD) {
                out_sample = CLIP_POS;
            } else if (sample < -THRESHOLD) {
                out_sample = CLIP_NEG;
            } else {
                out_sample = sample;
            }

            writeincr(out, out_sample);
        }

        // Toggle phase for next frame (0 -> 1, 1 -> 0)
        phase = phase + 1;
    }
}

