#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr int COEFF_LEN = 8;
constexpr int16 coeff[COEFF_LEN] = {1, 2, 3, 4, 4, 3, 2, 1};

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    constexpr int VECTOR_SIZE = 16;
    static int16 buffer[COEFF_LEN - 1 + VECTOR_SIZE];
    static int buf_ptr = 0;

    // Copy old samples to buffer
    for (int i = 0; i < COEFF_LEN - 1; ++i) {
        buffer[i] = buffer[i];
    }

    // Read new samples with vector load
    aie::vector<int16, VECTOR_SIZE> vec_in = readincr_v<VECTOR_SIZE>(in);

    // Store vector at potentially unaligned location
    aie::store_v(buffer + (COEFF_LEN - 1), vec_in);

    // Process each sample in the vector
    for (int i = 0; i < VECTOR_SIZE; ++i) {
        int32 acc = 0;
        for (int j = 0; j < COEFF_LEN; ++j) {
            acc += buffer[i + j] * coeff[j];
        }
        int16 result = acc >> 4;
        writeincr(out, result);
    }

    // Save for next iteration
    for (int i = 0; i < COEFF_LEN - 1; ++i) {
        buffer[i] = buffer[VECTOR_SIZE + i];
    }
}

