void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAP_COUNT = 4;
    int32_t sum = 0;
    int16_t delay_line[TAP_COUNT] = {0};
    int write_idx = 0;

    for (int n = 0; n < 128; n++) {
        // Read new sample and update delay line
        int16_t new_sample = readincr(in);
        int16_t oldest = delay_line[write_idx];
        delay_line[write_idx] = new_sample;
        write_idx = (write_idx + 1) % TAP_COUNT;

        // Update running sum: subtract oldest, add newest
        sum = sum - oldest + new_sample;

        // Compute average with proper scaling
        const int SHIFT_AMT = 2;  // divide by 4
        int16_t avg = (int16_t)(sum >> SHIFT_AMT);

        // Write as 32-bit to match cascade width assumption
        writeincr(out, (int32_t)avg);
    }
}

