void fir_stream_kernel(input_stream<int16>* in, output_stream<int16>* out) {
  const int TAPS = 4;
  const int PHASE = 0;
  const int ITERATIONS = 64;

  int16 coeff[TAPS] = {1, 2, 3, 4};
  int16 delay[TAPS] = {};

  for (int i = 0; i < ITERATIONS; i++) {
    int16 sample = readincr(in);

    int32 acc = 0;
    for (int t = TAPS - 1; t > 0; t--) {
      delay[t] = delay[t - 1];
    }
    delay[0] = sample;

    int idx = PHASE;
    for (int t = 0; t < TAPS; t++) {
      acc += (int32)delay[t] * (int32)coeff[idx];
      idx = (idx + 1) % TAPS;
    }

    int16 result = (int16)(acc >> 8);
    writeincr(out, result);
  }
}

void iir_stream_kernel(input_stream<int16>* in, output_stream<int16>* out) {
  const int ITERATIONS = 64;
