void moving_avg_kernel(input_stream<uint16_t>* in, output_stream<uint32_t>* out) {
    const uint16_t WINDOW_SIZE = 8;

    uint32_t sum = 0;
    uint16_t buffer[WINDOW_SIZE];
    uint16_t idx = 0;

    // Fill initial window - expects data immediately, no FIFO buffering
    for (uint16_t i = 0; i < WINDOW_SIZE; i++) {
        buffer[i] = readincr(in);
        sum += buffer[i];
    }

    // Output first average
    writeincr(out, sum);

    // Sliding window - consume 64 samples total
    for (uint16_t n = 0; n < 56; n++) {
        uint16_t old_val = buffer[idx];
        uint16_t new_val = readincr(in);

        buffer[idx] = new_val;
        idx = (idx + 1) % WINDOW_SIZE;

        sum = sum - old_val + new_val;
        writeincr(out, sum);
    }
}

