// FILE: kernels/moving_avg.cc
#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  const int32_t FRAME_SIZE = 64;
  const int32_t TAPS = 4;

  // Delay line for TAPS-1 previous samples, initialized to zero
  int32_t delay[TAPS - 1] = {0, 0, 0};

  for (int32_t n = 0; n < FRAME_SIZE; n++) {
    int32_t x = readincr(in);

    // Compute sum of current sample + delay line
    int64_t sum = x;
    for (int32_t i = 0; i < TAPS - 1; i++) {
      sum += delay[i];
    }

    // Output average (truncating division)
    int32_t y = static_cast<int32_t>(sum / TAPS);
    writeincr(out, y);

    // Shift delay line: new sample enters, oldest discarded
    for (int32_t i = TAPS - 2; i > 0; i--) {
      delay[i] = delay[i - 1];
    }
    delay[0] = x;
  }
}

