void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    const int N = 4;
    int16 history[N] = {0};
    int sum = 0;
    int idx = 0;

    for (int i = 0; i < N; ++i) {
        int16 val = readincr(in);
        history[i] = val;
        sum += val;
    }

    for (int i = 0; i < 64; ++i) {
        chess_prepare_for_pipelining
        int16 new_val = readincr(in);
        int16 old_val = history[idx];
        sum = sum - old_val + new_val;
        history[idx] = new_val;
        idx = (idx + 1) % N;
        int16 avg = sum / N;
        writeincr(out, avg);
    }
}

