void median_filter_kernel(
    input_stream<int16>* in,
    output_stream<int16>* out
) {
  aie::vector<int16, 8> window_data;
  aie::vector<int16, 8> sorted_data;

  // Process 256 input samples
  int sample_count = 256;

  for (int i = 0; i < sample_count; i++) {
    // Read 8 int16 values from input stream
    window_data = readincr_v<8>(*in);

    // Simple bubble sort for median (3-element window simulation)
    int16 a = window_data[0];
    int16 b = window_data[1];
    int16 c = window_data[2];

    if (a > b) { int16 tmp = a; a = b; b = tmp; }
    if (b > c) { int16 tmp = b; b = c; c = tmp; }
    if (a > b) { int16 tmp = a; a = b; b = tmp; }

    // Median is b (middle value)
    int16 median = b;

    // Replicate median across vector for output
    sorted_data = aie::broadcast<int16, 8>(median);

    // Write 8 output samples
    writeincr_v<8>(*out, sorted_data);
  }
}

