#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void decimate_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // Decimation factor: output every Nth sample
    const int32_t DECIM_FACTOR = 4;
    const int32_t BLOCK_SIZE = 64;
    const int32_t PHASE = 0;

    for (int32_t b = 0; b < BLOCK_SIZE; b++) {
        // Read and discard samples before the phase position
        for (int32_t skip = 0; skip < PHASE; skip++) {
            readincr(in);
        }

        // Output the sample at current phase
        int32_t sample = readincr(in);
        writeincr(out, sample);

        // Read and discard remaining samples in decimation period
        for (int32_t skip = PHASE + 1; skip < DECIM_FACTOR; skip++) {
            readincr(in);
        }
    }

    // Flush remaining samples to ensure DMA descriptor completion
    // Hardware requires explicit drain of stream buffer
    for (int32_t drain = 0; drain < 16; drain++) {
        readincr(in);
    }
}

