void histogram_kernel(input_stream<int16>* data_in,
                      output_stream<int32>* hist_out) {
  aie::accum<acc48, 8> histogram;
  histogram = aie::zeros<acc48, 8>();

  const int num_samples = 256;
  const int num_bins = 8;

  for (int i = 0; i < num_samples; ++i) {
    chess_prepare_for_pipelining
    int16 sample = readincr(data_in);

