    aie::vector<int16, 8> ones = aie::broadcast<int16, 8>(1);

    // Load current histogram state
    aie::vector<int32, 8> hist_vec = aie::srs(histogram, 0);

    // Increment the appropriate bin
    for (int j = 0; j < num_bins; ++j) {
      if (j == bin_idx) {
        hist_vec[j]++;
      }
