#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr int TAPS = 8;
constexpr int COEFFS[TAPS] = {1, 2, 3, 4, 4, 3, 2, 1};

void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
    int32 history[TAPS] = {0};
    aie::accum<acc80, 4> acc = aie::zeros<acc80, 4>();

    for (int i = 0; i < 64; i++) {
        chess_prepare_for_pipelining

        for (int j = TAPS - 1; j > 0; j--) {
            history[j] = history[j - 1];
        }
        history[0] = readincr(in);

        for (int t = 0; t < TAPS; t += 4) {
            aie::vector<int32, 4> hist_vec = aie::load_v<4>(&history[t]);
            aie::vector<int32, 4> coeff_vec = aie::load_v<4>(&COEFFS[t]);
            acc = aie::mac(acc, hist_vec, coeff_vec);
        }

        int32 result = acc.to_vector<int32>(0)[0];
        writeincr(out, result);
    }
}

