void fir_int32_stream(input_stream<int32>* in, output_stream<int32>* out) {
    const int N = 8;
    int32 coeff[N] = {32768, 16384, 8192, 4096, 2048, 1024, 512, 256};
    int32 state[N] = {0};
    int32 sum = 0;

    for (int i = 0; i < 64; i++) {
        chess_prepare_for_pipelining
        int32 val = readincr(in);
        state[0] = val;
        sum = 0;
        for (int j = 0; j < N; j++) {
            sum += (state[j] * coeff[j]) >> 14;
        }
        for (int j = N-1; j > 0; j--) {
            state[j] = state[j-1];
        }
        writeincr(out, sum);
    }
}

