#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

const int16 THRESHOLD_HIGH = 1000;
const int16 THRESHOLD_LOW = -1000;

void threshold_clip(input_stream<int16> *in, output_stream<int16> *out) {
    const int SAMPLES = 64;
    int16 val;

    for (int i = 0; i < SAMPLES; i++) {
        val = readincr(in);

        if (val > THRESHOLD_HIGH) {
            val = THRESHOLD_HIGH;
        } else if (val < THRESHOLD_LOW) {
            val = THRESHOLD_LOW;
        }

        writeincr(out, val);
    }
}

