void prefix_sum(input_stream<int16>* in, output_stream<int32>* out) {
    const int16 header_count = readincr(in);
    const int32 num_iterations = header_count;

    int32 running_sum = 0;

    for (int32 i = 0; i < num_iterations; i++) {
        int16 val = readincr(in);
        running_sum += val;
        writeincr(out, running_sum);
    }
}

