#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void decimate_kernel(input_window<int32>* in, output_window<int32>* out) {
    const int DECIMATION_FACTOR = 4;
    const int ITERATIONS = 32;

    for (int i = 0; i < ITERATIONS; i++) {
        chess_prepare_for_pipelining
        int32 sum = 0;
        for (int d = 0; d < DECIMATION_FACTOR; d++) {
            int32 sample = window_readincr(in);
            sum += sample;
        }
        int32 average = sum / DECIMATION_FACTOR;
        window_writeincr(out, average);
    }
}

