#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void prefix_sum(input_stream<int16>* in1, input_stream<int16>* in2, 
                input_stream<int16>* in3, input_stream<int16>* in4,
                output_stream<int16>* out1, output_stream<int16>* out2,
                output_stream<int16>* out3, output_stream<int16>* out4) {
    const int16 samples_per_tile = 256;
    const int16 shift_bits = 0;

    int32 running_sum = 0;

    for (int i = 0; i < samples_per_tile; i++) {
        int16 s1 = readincr(in1);
        int16 s2 = readincr(in2);
        int16 s3 = readincr(in3);
        int16 s4 = readincr(in4);
        running_sum += s1 + s2 + s3 + s4;
        int16 output_val = (int16)(running_sum >> shift_bits);
        writeincr(out1, output_val);
        writeincr(out2, output_val);
        writeincr(out3, output_val);
        writeincr(out4, output_val);
    }
}

