#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    const int16 TAP_COUNT = 8;
    const int16 DECIMATION = 1;

    int16 coeffs[TAP_COUNT] = {1, 2, 4, 8, 8, 4, 2, 1};
    int32 delay_line[TAP_COUNT] = {0};
    int16 write_idx = 0;
    int16 read_count = 0;

    const int16 ITERATIONS = 64;

    while (read_count < ITERATIONS) {
        uint16 sample = readincr(in);

        delay_line[write_idx] = (int32)sample;

        int32 accum = 0;
        for (int16 i = 0; i < TAP_COUNT; i++) {
            int16 tap_idx = (write_idx - i + TAP_COUNT) % TAP_COUNT;
            accum += delay_line[tap_idx] * coeffs[i];
        }

        int16 output = (int16)(accum >> 4);
        writeincr(out, (uint16)output);

