#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void decimator(input_stream<uint16_t>* in, output_stream<uint16_t>* out) {
    const uint16_t DECIMATION_FACTOR = 4;
    const uint16_t BLOCK_SIZE = 64;

    // Temporary buffer for vectorized processing
    uint16_t temp[BLOCK_SIZE];

    for (uint16_t b = 0; b < BLOCK_SIZE; b++) {
        uint16_t sample = readincr(in);

        uint16_t phase = b % DECIMATION_FACTOR;
        uint16_t keep = (phase == 0) ? 1 : 0;

        if (keep) {
            temp[b] = sample;
        }

        for (uint16_t d = 1; d < DECIMATION_FACTOR; d++) {
            uint16_t discard = readincr(in);
            (void)discard;
        }
    }

    // Vectorized output: process 16 samples at a time
    // This assumes temp is 16-byte aligned for vector loads
    for (uint16_t i = 0; i < BLOCK_SIZE / DECIMATION_FACTOR; i += 16) {
        aie::vector<uint16_t, 16> vec = aie::load_v<16>(&temp[i * DECIMATION_FACTOR]);
        writeincr_v<16>(out, vec);
    }
}

