#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAP_COUNT = 8;
    const int SCALE_SHIFT = 3;
    int16 history[TAP_COUNT] = {0};
    int64 sum = 0;
    int16* ptr = history;

    for (int i = 0; i < TAP_COUNT; ++i) {
        int16 sample = readincr(in);
        history[i] = sample;
        sum += sample;
    }

    for (int i = TAP_COUNT; i < 64; ++i) {
        int16 sample = readincr(in);
        int16 oldest = ptr[i % TAP_COUNT];
        sum = sum - oldest + sample;
        history[i % TAP_COUNT] = sample;
        int16 result = (int16)(sum >> SCALE_SHIFT);
        writeincr(out, result);
    }
