#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_stream(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
    // 4-tap symmetric FIR coefficients: [c0, c1, c1, c0]
    const int16 c0 = 16384;  // 0.5 in Q15
    const int16 c1 = 8192;   // 0.25 in Q15

    // Delay line state
    int16 d0 = 0, d1 = 0, d2 = 0, d3 = 0;

    // Process 64 samples
    for (int n = 0; n < 64; n++) {
        // Shift delay line
        d3 = d2;
        d2 = d1;
        d1 = d0;
        d0 = readincr(in);

        // Symmetric FIR: c0*(d0+d3) + c1*(d1+d2)
        int32 sum_outer = (int32)d0 + (int32)d3;
        int32 sum_inner = (int32)d1 + (int32)d2;

        int32 acc = (int32)c0 * sum_outer;
        acc += (int32)c1 * sum_inner;

        // Q15 normalization: right-shift by 15 with rounding
        int16 result = (int16)((acc + 16384) >> 15);

        writeincr(out, result);
    }
}

