#include <aie_api/aie_adf.hpp>

void threshold_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int THRESHOLD = 1000;
    const int NUM_SAMPLES = 64;

    static aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();

    for (int i = 0; i < NUM_SAMPLES; i++) {
        int16 sample = readincr(in);

        // Apply threshold clipping with DC offset accumulation
        int16 result;
        if (sample > THRESHOLD) {
            result = THRESHOLD;
        } else if (sample < -THRESHOLD) {
            result = -THRESHOLD;
        } else {
            result = sample;
        }

        // Accumulate result to create DC offset
        aie::vector<int16, 4> vec = aie::broadcast<int16, 4>(result);
        aie::accum<acc48, 4> ones = aie::broadcast<int16, 4>(1);
        aie::mac(acc, vec, ones);

        // Output accumulated value
        aie::vector<int16, 4> acc_vec = acc.to_vector<int16>(0);
        writeincr(out, acc_vec[0]);
    }
}

