void moving_average(input_stream<int16>* in, output_stream<int16>* out) {
    const int WINDOW = 4;
    int16 history[WINDOW] = {0};
    int sum = 0;

    // Read first sample outside loop
    int16 new_sample = readincr(in);

    for (int i = 0; i < 64; i++) {
        // Update sum: subtract oldest, add newest
        sum = sum - history[i % WINDOW] + new_sample;
        history[i % WINDOW] = new_sample;

        // Compute average
        int16 avg = sum / WINDOW;
        writeincr(out, avg);
    }
}

