#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_window<int32>* in, output_window<int32>* out) {
    const int PHASES = 4;
    const int32 coeffs[PHASES] = { 10, -20, 30, -40 };
    int32 state[PHASES] = { 0, 0, 0, 0 };
    const int BLOCK_SIZE = 32;

    auto in_ptr = aie::begin_vector<8>(in);
    auto out_ptr = aie::begin_vector<8>(out);

    for (int i = 0; i < BLOCK_SIZE/8; ++i) {
        aie::vector<int32,8> samples = aie::load_v<8>(in_ptr++);

        for (int j = 0; j < 8; ++j) {
            int32 sample = samples[j];
            state[0] = state[1];
            state[1] = state[2];
            state[2] = state[3];
            state[3] = sample;

            int64 accum = 0;
            for (int p = 0; p < PHASES; ++p) {
                accum += (int64)state[p] * coeffs[p];
            }
            int32 result = (int32)(accum >> 2);
            samples[j] = result;
        }

        aie::store_v(out_ptr++, samples);
    }
}

