#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void decimate_kernel(input_stream<uint16>* __restrict in,
                     output_stream<uint16>* __restrict out) {
    // Decimation factor: keep 1 of every 4 samples
    const int decim_factor = 4;
    const int samples_per_block = 64;

    // Process 64 output samples (256 input samples)
    for (int i = 0; i < samples_per_block; i++) {
        // Read and discard decim_factor-1 samples
        uint16 kept = readincr(in);
        for (int j = 1; j < decim_factor; j++) {
            uint16 discard = readincr(in);
            (void)discard; // suppress unused warning
        }
        writeincr(out, kept);
    }
}

