#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

const int SCALE_FACTOR = 3;
const int SHIFT_AMOUNT = 5;

void scale_shift(input_stream<int16>* in, output_stream<int16>* out) {
    const int NUM_SAMPLES = 64;
    for (int i = 0; i < NUM_SAMPLES; i++) {
        chess_prepare_for_pipelining
        int16 val = readincr(in);
        int32 scaled = val * SCALE_FACTOR;
        int32 shifted = scaled + SHIFT_AMOUNT;
        int16 result;
        if (shifted > 32767) result = 32767;
        else if (shifted < -32768) result = -32768;
        else result = (int16)shifted;
        writeincr(out, result);
    }
}

