#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32>* in, output_stream<int32>* out, int32* coeff_ptr) {
    const int TAPS = 4;
    int32 coeff[TAPS];

    for (int i = 0; i < TAPS; i++) {
        coeff[i] = coeff_ptr[i];
    }

    int32 buffer[TAPS] = {0};
    int buf_idx = 0;

    for (int i = 0; i < 64; i++) {
        chess_prepare_for_pipelining

        int32 sample = readincr(in);
        buffer[buf_idx] = sample;

        int32 acc = 0;
        for (int j = 0; j < TAPS; j++) {
            int coeff_idx = (buf_idx - j + TAPS) % TAPS;
            acc += buffer[coeff_idx] * coeff[j];
        }

        writeincr(out, acc);

        buf_idx = (buf_idx + 1) % TAPS;
    }
}

