#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_int32_stream(input_stream<int32>* in, output_stream<int32>* out) {
    const int COEFF[4] = {1, 2, 3, 4};
    int32 state[4] = {0, 0, 0, 0};

    for (int i = 0; i < 32; ++i) {
        int32 sample = readincr(in);

        // Shift state
        for (int j = 3; j > 0; --j) {
            state[j] = state[j-1];
        }
        state[0] = sample;

        // Compute FIR output
        int32 acc = 0;
        for (int j = 0; j < 4; ++j) {
            acc += state[j] * COEFF[j];
        }

        writeincr(out, acc);
    }
}

