#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAP_COUNT = 8;
    const int SCALE = 3;  // shift right by 3 to divide by 8

    int16 history[TAP_COUNT] = {0};
    int32 sum = 0;

    for (int i = 0; i < TAP_COUNT; ++i) {
        int16 sample = readincr(in);
        history[i] = sample;
        sum += sample;
    }

    for (int i = TAP_COUNT; i < 64; ++i) {
        int32 avg = sum >> SCALE;
        writeincr(out, (int16)avg);

        int16 new_sample = readincr(out);
        int16 old_sample = history[i % TAP_COUNT];

        sum = sum - old_sample + new_sample;
        history[i % TAP_COUNT] = new_sample;
    }

    for (int i = 0; i < TAP_COUNT; ++i) {
        int32 avg = sum >> SCALE;
        writeincr(out, (int16)avg);

        sum -= history[i];
    }
}

