#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// AIE-ML has 64KB tile memory; AIE has 32KB. 
// This constant controls tap buffer allocation size.
// 8192 int32 samples = 32KB (safe for AIE)
// 16384 int32 samples = 64KB (safe for AIE-ML)
constexpr int HISTORY_SIZE = 16384;
constexpr int AVG_WINDOW = 8;

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
  // Static buffer sized for 32KB assumption
  static int32_t history[HISTORY_SIZE];
  static int write_idx = 0;
  static int num_samples = 0;

  for (int n = 0; n < 128; n++) {
    int32_t sample = readincr(in);

    history[write_idx] = sample;
    write_idx = (write_idx + 1) % HISTORY_SIZE;
    if (num_samples < HISTORY_SIZE) num_samples++;

    int32_t sum = 0;
    int count = (num_samples < AVG_WINDOW) ? num_samples : AVG_WINDOW;
    int read_idx = (write_idx + HISTORY_SIZE - count) % HISTORY_SIZE;

    for (int i = 0; i < count; i++) {
      int idx = (read_idx + i) % HISTORY_SIZE;
      sum += history[idx];
    }

    int32_t avg = sum / count;
    writeincr(out, avg);
  }
}

