void median_filter_kernel(aie::input_stream<int16>* in_data,
                          aie::output_stream<int16>* out_primary,
                          aie::output_stream<int16>* out_secondary) {
  aie::vector<int16, 8> window = aie::zeros<int16, 8>();

  for (int i = 0; i < 256; i++) {
    chess_prepare_for_pipelining
    int16 val = readincr(in_data);
    window = aie::shuffle_down(window, 1);
    window[0] = val;

    // Compute median from 8-element window
    int16 a = window[0], b = window[1], c = window[2], d = window[3];
    int16 e = window[4], f = window[5], g = window[6], h = window[7];

    // Simple sorting network for median
    if (a > b) { int16 tmp = a; a = b; b = tmp; }
    if (c > d) { int16 tmp = c; c = d; d = tmp; }
    if (e > f) { int16 tmp = e; e = f; f = tmp; }
    if (g > h) { int16 tmp = g; g = h; h = tmp; }

    if (a > c) { int16 tmp = a; a = c; c = tmp; }
    if (b > d) { int16 tmp = b; b = d; d = tmp; }
    if (e > g) { int16 tmp = e; e = g; g = tmp; }
    if (f > h) { int16 tmp = f; f = h; h = tmp; }

    int16 median = (d + e) / 2;

    // Write median to both output ports
    writeincr(out_primary, median);
    writeincr(out_primary, median);
  }
}

