void threshold_clip(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  const int32_t UPPER_THRESH = 1000;
  const int32_t LOWER_THRESH = -1000;
  const int32_t FRAMESIZE = 64;

  unsigned int start_time = get_cycles();

  for (int i = 0; i < FRAMESIZE; i++) chess_prepare_for_pipelining {
    int32_t sample = readincr(in);
    int32_t clipped;
    if (sample > UPPER_THRESH) {
      clipped = UPPER_THRESH;
    } else if (sample < LOWER_THRESH) {
      clipped = LOWER_THRESH;
    } else {
      clipped = sample;
    }
    writeincr(out, clipped);
  }

  unsigned int end_time = get_cycles();
  int latency = end_time - start_time;
  if (latency < 0) {
    latency += 0xFFFFFFFF;
  }
  int32_t* profile_ptr = (int32_t*)0x40000;
  *profile_ptr = latency;
}

