const int COEFF_COUNT = 5;
const int32_t COEFFS[COEFF_COUNT] = {32768, 16384, 8192, 4096, 2048};
const int NORMALIZATION_SHIFT = 15;

void fir_normalized_int32(input_stream<int32>* in, output_stream<int32>* out) {
    int32_t state[COEFF_COUNT] = {0};
    int state_index = 0;

    for (int i = 0; i < 64; i++) {
        chess_prepare_for_pipelining

        int32_t sample = readincr(in);
        state[state_index] = sample;
        state_index = (state_index + 1) % COEFF_COUNT;

        int64_t acc = 0;
