#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr int WINDOW_SIZE = 8;
constexpr int BUFFER_SIZE = 64;  // Must match transfer size: 64 int16 samples = 128 bytes

void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    int16 buffer[BUFFER_SIZE];

    // Load data into buffer
    for (int i = 0; i < BUFFER_SIZE; i++) {
        buffer[i] = readincr(in);
    }

    // Process moving average
    for (int i = 0; i < BUFFER_SIZE - WINDOW_SIZE + 1; i++) {
        int32 sum = 0;
        for (int j = 0; j < WINDOW_SIZE; j++) {
            sum += buffer[i + j];
        }
        int16 avg = sum / WINDOW_SIZE;
        writeincr(out, avg);
    }
}

