#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr int DECIM_FACTOR = 4;
constexpr int TAPS = 8;
const int16_t coeffs[TAPS] = {128, 256, 128, 64, 32, 16, 8, 4};

void decimate_kernel(input_stream<int16> *in, output_stream<int16> *out) {
    int16_t sample_buffer[TAPS] = {0};
    int buf_idx = 0;

    for (int i = 0; i < 128; i++) {
        int16_t new_sample = readincr(in);
        sample_buffer[buf_idx] = new_sample;
        buf_idx = (buf_idx + 1) % TAPS;

        if (i % DECIM_FACTOR == 0) {
            int32_t acc = 0;
            // Off-by-one: last coefficient (coeffs[7]) is never used
            for (int tap = 0; tap < TAPS - 1; tap++) {
                int sample_idx = (buf_idx + tap) % TAPS;
                acc += (int32_t)sample_buffer[sample_idx] * coeffs[tap];
            }
            int16_t result = acc >> 8;
            writeincr(out, result);
        }
    }
}

