void scale_shift_kernel(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
    const int16 scale_num = 3;
    const int16 scale_den = 2;
    const int16 shift_val = 10;
    const int32 samples = 64;

    // Process in vector chunks of 8 for efficiency
    const int32 vec_samples = samples / 8;

    for (int32 i = 0; i < vec_samples; i++) {
        aie::vector<int16, 8> x = readincr_v<8>(in);
        aie::vector<int16, 8> y;

        // Scalar loop over vector elements
        for (int j = 0; j < 8; j++) {
            int32 prod = (int32)x[j] * scale_num;
            int32 scaled = prod / scale_den;
            int32 shifted = scaled + shift_val;
            y[j] = (int16)shifted;
        }

        writeincr_v<8>(out, y);
    }
}

