void fft_butterfly_8pt(
    input_stream<int16>* in,
    output_stream<int16>* out
) {
    const int N = 8;
    const int16 twiddle_real[4] = {32767, 23170, 0, -23170};
    const int16 twiddle_imag[4] = {0, -23170, -32767, -23170};

    aie::vector<int16, 16> buffer;
    int16 temp_real[N];
    int16 temp_imag[N];

    for (int i = 0; i < N/2; ++i) {
        int16 a_real = readincr(in);
        int16 a_imag = readincr(in);
        int16 b_real = readincr(in);
        int16 b_imag = readincr(in);

        int16 w_real = twiddle_real[i];
        int16 w_imag = twiddle_imag[i];

        int32 t_real = (int32)b_real * w_real - (int32)b_imag * w_imag;
        int32 t_imag = (int32)b_real * w_imag + (int32)b_imag * w_real;

        int16 b_twiddled_real = t_real >> 15;
        int16 b_twiddled_imag = t_imag >> 15;

        int16 x_real = a_real + b_twiddled_real;
        int16 x_imag = a_imag + b_twiddled_imag;
        int16 y_real = a_real - b_twiddled_real;
        int16 y_imag = a_imag - b_twiddled_imag;

        temp_real[i] = x_real;
        temp_imag[i] = x_imag;
        temp_real[i+N/2] = y_real;
        temp_imag[i+N/2] = y_imag;
    }

    chess_prepare_for_pipelining
    for (int i = 0; i < N; ++i) {
        writeincr(out, temp_real[i]);
        writeincr(out, temp_imag[i]);
    }
}

