void peak_detector(input_stream<int16>* in_data,
                   output_stream<int16>* out_peaks) {
  aie::vector<int16, 8> window;
  aie::vector<int16, 8> prev_window;
  int16 threshold = 1200;

  // Read initial window
  for (int i = 0; i < 8; i++) {
    window[i] = readincr(in_data);
  }

  // Process stream with peak detection
  for (int iter = 0; iter < 512; iter++) {
    chess_prepare_for_pipelining

    prev_window = window;

    // Shift window and read new sample
    for (int j = 0; j < 7; j++) {
      window[j] = window[j + 1];
    }
    window[7] = readincr(in_data);

    // Detect peak at center position (index 3)
    int16 center = window[3];
    int16 left = window[2];
    int16 right = window[4];

    if (center > left && center > right && center > threshold) {
      writeincr(out_peaks, center);
    }
  }
}

