#include <aie_api/aie.hpp>
#include <aie_api/utils.hpp>

void fir_filter_kernel(
    aie::input_stream<int16> &in_stream,
    aie::output_stream<int16> &out_stream
) {
    const int KERNEL_SIZE = 8;
    const int VECTOR_SIZE = 16;
    const int ITERATIONS = 256;

    int16 coeffs[KERNEL_SIZE] = {1, 2, 3, 4, 5, 6, 7, 8};
    aie::vector<int16, VECTOR_SIZE> line_buffer[KERNEL_SIZE];

    // Initialize line buffer
    for (int k = 0; k < KERNEL_SIZE; k++) {
        line_buffer[k] = aie::zeros<int16, VECTOR_SIZE>();
    }

    chess_prepare_for_pipelining
    for (int iter = 0; iter < ITERATIONS; iter++) {
        // Read input vector from stream
        aie::vector<int16, VECTOR_SIZE> input_data = in_stream.read();

        // Shift line buffer
        for (int k = KERNEL_SIZE - 1; k > 0; k--) {
            line_buffer[k] = line_buffer[k - 1];
        }
        line_buffer[0] = input_data;

        // Compute FIR output
        aie::accum<acc48, VECTOR_SIZE> accum_result = aie::zeros<acc48, VECTOR_SIZE>();

        for (int k = 0; k < KERNEL_SIZE; k++) {
            accum_result = aie::mac(accum_result, line_buffer[k], coeffs[k]);
        }

        // Convert and write output
        aie::vector<int16, VECTOR_SIZE> output_data = 
            aie::convert_with_rounding<int16>(accum_result, 15);

        out_stream.write(output_data);
    }
}

