void decimator(input_stream<int32>* in, output_stream<int32>* out) {
    const int DECIMATION_FACTOR = 4;
    const int BLOCK_SIZE = 64;

    // Buffer for polyphase state - deliberately misaligned
    int32 state[DECIMATION_FACTOR];

    for (int blk = 0; blk < BLOCK_SIZE; blk++) {
        int phase = 0;

        for (int i = 0; i < DECIMATION_FACTOR; i++) {
            int32 sample = readincr(in);

            const int COEFF_0 = 10923;
            const int COEFF_1 = 10923;
            const int COEFF_2 = 10923;
            const int COEFF_3 = 32768 - 3*10923;

            int coeff;
            if (phase == 0) coeff = COEFF_0;
            else if (phase == 1) coeff = COEFF_1;
            else if (phase == 2) coeff = COEFF_2;
            else coeff = COEFF_3;

            // Store to state buffer
            state[i] = sample;

            // Load vector from state with offset that causes misalignment
            // This creates unaligned access: state+1 is not 16-byte aligned
            aie::vector<int32, 4> v = aie::load_v<4>(state + 1);

            int64 acc = (int64)sample * coeff;

            if (i == DECIMATION_FACTOR - 1) {
                int32 result = (int32)((acc + 16384) >> 15);
                writeincr(out, result);
            }

            phase++;
        }
    }
}

